import React, { useState } from 'react';
import { Alert, Pressable, SafeAreaView, ScrollView, StyleSheet, Text, TextInput, View } from 'react-native';
import { registerUserWithPhone } from '../services/firebaseService';
import { NativeStackScreenProps } from '@react-navigation/native-stack';
import { RootStackParamList } from '../navigation/AppNavigator';
import TopNav from '../components/TopNav';

type Props = NativeStackScreenProps<RootStackParamList, 'Signup'>;

const SignupScreen = ({ navigation }: Props) => {
  const [name, setName] = useState('');
  const [phone, setPhone] = useState('');
  const [role, setRole] = useState<'customer' | 'owner'>('customer');
  const [loading, setLoading] = useState(false);
  const [errorMessage, setErrorMessage] = useState('');

  const handleSignup = async () => {
    if (!name || !phone) {
      setErrorMessage('Please provide your name and phone number.');
      return;
    }
    setLoading(true);
    setErrorMessage('');
    try {
      await registerUserWithPhone(name.trim(), phone.trim(), role);
    } catch (error: any) {
      setErrorMessage(error.message || 'Unable to create account.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <SafeAreaView style={styles.container}>
      <View style={styles.backgroundCircleTop} />
      <View style={styles.backgroundCircleBottom} />
      <TopNav />
      <ScrollView contentContainerStyle={styles.content} keyboardShouldPersistTaps="handled">
        <View style={styles.heroCard}>
          <Text style={styles.brand}>Thanni CAN</Text>
          <Text style={styles.title}>Create your delivery account</Text>
          <Text style={styles.subtitle}>Select your role and get started with fast water delivery.</Text>
        </View>
        <View style={styles.formCard}>
          <TextInput
            style={styles.input}
            placeholder="Full name"
            placeholderTextColor="#9CA3AF"
            value={name}
            onChangeText={setName}
          />
          <TextInput
            style={styles.input}
            placeholder="Phone number"
            placeholderTextColor="#9CA3AF"
            value={phone}
            keyboardType="phone-pad"
            onChangeText={setPhone}
          />
          <Text style={styles.helperText}>Include country code, e.g. +91 99000 01111</Text>
          {errorMessage ? <Text style={styles.errorText}>{errorMessage}</Text> : null}
          <Text style={styles.roleLabel}>Account type</Text>
          <View style={styles.roleRow}>
            <Pressable
              style={[styles.roleButton, role === 'customer' && styles.roleButtonActive]}
              onPress={() => setRole('customer')}
            >
              <Text style={[styles.roleText, role === 'customer' && styles.roleTextActive]}>Customer</Text>
            </Pressable>
            <Pressable
              style={[styles.roleButton, role === 'owner' && styles.roleButtonActive]}
              onPress={() => setRole('owner')}
            >
              <Text style={[styles.roleText, role === 'owner' && styles.roleTextActive]}>Owner</Text>
            </Pressable>
          </View>
          <Pressable style={styles.button} onPress={handleSignup} disabled={loading}>
            <Text style={styles.buttonText}>{loading ? 'Creating account...' : 'Create account'}</Text>
          </Pressable>
        </View>
        <View style={styles.footer}>
          <Text style={styles.footerText}>Already have an account?</Text>
          <Pressable onPress={() => navigation.navigate('Login')}>
            <Text style={styles.footerLink}>Sign in</Text>
          </Pressable>
        </View>
      </ScrollView>
    </SafeAreaView>
  );
};

const styles = StyleSheet.create({
  container: {
    flex: 1,
    backgroundColor: '#E9F6FF'
  },
  backgroundCircleTop: {
    position: 'absolute',
    top: -80,
    right: -80,
    width: 220,
    height: 220,
    borderRadius: 110,
    backgroundColor: '#2DBCFE',
    opacity: 0.18
  },
  backgroundCircleBottom: {
    position: 'absolute',
    bottom: -70,
    left: -70,
    width: 180,
    height: 180,
    borderRadius: 90,
    backgroundColor: '#ACD6FF',
    opacity: 0.24
  },
  content: {
    flexGrow: 1,
    justifyContent: 'center',
    padding: 24
  },
  heroCard: {
    marginBottom: 20,
    padding: 24,
    borderRadius: 28,
    backgroundColor: 'rgba(255,255,255,0.92)',
    boxShadow: '0px 8px 24px rgba(0, 0, 0, 0.10)'
  },
  brand: {
    fontSize: 28,
    fontWeight: '900',
    color: '#00344B',
    marginBottom: 12
  },
  title: {
    fontSize: 24,
    fontWeight: '800',
    color: '#0F172A',
    marginBottom: 8
  },
  subtitle: {
    fontSize: 15,
    lineHeight: 22,
    color: '#475569'
  },
  formCard: {
    backgroundColor: 'white',
    padding: 24,
    borderRadius: 26,
    boxShadow: '0px 8px 24px rgba(0, 0, 0, 0.10)'
  },
  input: {
    backgroundColor: '#F8FAFF',
    borderRadius: 16,
    padding: 16,
    marginBottom: 14,
    borderWidth: 1,
    borderColor: '#E2E8F0',
    color: '#0F172A'
  },
  roleLabel: {
    color: '#4B5563',
    marginBottom: 10,
    fontSize: 14,
    fontWeight: '700'
  },
  roleRow: {
    flexDirection: 'row',
    gap: 12,
    marginBottom: 24
  },
  roleButton: {
    flex: 1,
    backgroundColor: '#F8FAFF',
    borderRadius: 16,
    paddingVertical: 14,
    borderWidth: 1,
    borderColor: '#D1D5DB',
    alignItems: 'center'
  },
  roleButtonActive: {
    backgroundColor: '#006289',
    borderColor: '#006289'
  },
  roleText: {
    color: '#334155',
    fontWeight: '700'
  },
  roleTextActive: {
    color: 'white'
  },
  button: {
    backgroundColor: '#006289',
    borderRadius: 16,
    alignItems: 'center',
    padding: 16
  },
  buttonText: {
    color: 'white',
    fontSize: 16,
    fontWeight: '800'
  },
  footer: {
    flexDirection: 'row',
    justifyContent: 'center',
    marginTop: 18
  },
  footerText: {
    color: '#475569',
    marginRight: 6
  },
  footerLink: {
    color: '#006289',
    fontWeight: '800'
  },
  helperText: {
    color: '#64748B',
    marginBottom: 10,
    fontSize: 12
  },
  errorText: {
    color: '#DC2626',
    fontWeight: '700',
    marginBottom: 12
  }
});

export default SignupScreen;
